import json,os
p=r"D:\YJ-Agent\project\ideation\runs\2026-06-17_run-001_nca-wm-medseg-uq\03_raw_candidates\S1-gap.jsonl"
DATA_S='{"S1-01": {"one_liner": "NCA cell state 内置双通道 UQ，每个细胞在局部传播时同步传递 aleatoric 和 epistemic 校准置信度", "problem": "M3D-NCA MICCAI2023 和 arXiv:2605.26726 均指出 NCA NQM 质量指标只能给出全局单值，无法在像素级区分 aleatoric 和 epistemic 不确定性。arXiv:2603.18792 指出现有 UQ 方法在 aleatoric-epistemic 纠缠上缺乏系统评估标准。临床部署时医生无法判断 NCA 哪类失败需更多数据、哪类需换模型。", "approach": "1: NCA cell state 增加 aleatoric head Dirichlet 和 epistemic head 3x mini-NCA ensemble；2: 多标注员数据 QUBIQ 监督 aleatoric，MRI-to-CT domain shift 拉开 epistemic；3: ACDC/BraTS/ISIC 上与 SDE-UNet、M3D-NCA NQM、MC-Dropout 比较 pixelwise ECE + OOD AUROC + Dice", "why_new": "现有 NCA UQ 从全局稳定性代理角度估计；我从 cell-local UQ propagation 角度每个细胞局部通信时同步传递双通道置信度——现有 NCA UQ 均为全局终态视角，本条首次做 cell-local 视角"}, "S1-02": {"one_liner": "NCA 随机多轨迹迭代作为 conformal 集合内生来源，给分割边界贴上有统计保证的置信区间", "problem": "MICCAI 2025 ConSeMa 指出形态学预测集依赖黑盒模型外部膨胀后处理，无法利用模型内部迭代动力学。Conformal Risk Control ICLR2024 的 covariate shift 扩展被作者标为 future work。NCA 随机动力学天然产生多收敛轨迹，是 conformal 集合的内生来源，但从未被形式化利用。", "approach": "1: K=50 次不同初始噪声 NCA 末态集合作为 conformal non-conformity score 来源；2: 推导基于 NCA 集合差异的形态学预测集，验证 exchangeability 假设下 coverage 保证；3: domain-shifted 数据 ACDC 跨扫描仪上与 ConSeMa、SACP 比较 coverage-Dice Pareto 前沿", "why_new": "现有 conformal segmentation 从外生视角（黑盒模型+后处理膨胀）；我从内生视角利用 NCA 迭代随机性构造 conformal 集合，coverage 保证来自 NCA 收敛分布——内生 vs 外生是本质差异"}, "S1-03": {"one_liner": "实时轨迹光谱监控让 NCA 在 OOD 输入时自动减速迭代并发出警报，而非静默误分割", "problem": "Med-NCA arXiv:2302.03473 和 Generalization NCA arXiv:2408.15557 均把 OOD 检测列为 limitation：OOD 输入下 NCA 仍收敛到错误固定点不发出信号。photonic NCA alive-cell 代理 arXiv:2309.13186 只针对简单分类，医学分割场景下 alive-cell 与分割质量相关性未被系统研究。静默失败等于临床误诊。", "approach": "1: 系统研究 alive-cell entropy、细胞状态轨迹曲率、局部通讯矩阵谱半径与 Dice 下降的 rank correlation，建立 OOD 代理指标集；2: 设计迭代早停+警报机制，代理指标进入危险区域则停止并返回高不确定掩码；3: 8 种 OOD 场景下评测 AUROC FPR95 对比 NQM MC-Dropout Deep Ensemble", "why_new": "现有 NCA OOD 从外部 wrapper 代理角度（训练后加检测器）；我从 NCA 迭代过程实时轨迹光谱监控角度原位检测，不修改架构不重训练——过程诊断 vs 现有终态诊断"}, "S1-04": {"one_liner": "NCA cell state grid 即世界状态，加轻量 temporal head 让 NCA 在细胞层级预测下一帧心脏分割图", "problem": "MedSegDiffNCA arXiv:2501.02447 limitation 明确指出当前 NCA-Diffusion 只处理单帧，无法利用医学序列时间依赖性。arXiv:2511.16333 NeurIPS2025 Workshop 把 temporal consistency 和 trajectory-level UQ 列为医学 WM 首要 gap。NCA 迭代特性天然对应时间展开，但从未被形式化为序列世界模型。", "approach": "1: NCA cell state grid 定义为时间步 t 世界状态，加轻量 temporal transition head GRU-cell 参数小于1M 预测下一步；2: 心脏电影 MRI 序列 ACDC time series 训练，前 T-1 帧 NCA 收敛状态预测第 T 帧分割；3: 评估时序 Dice、边界一致性、missed-frame 插值质量，对比 3D-UNet 时序 nnUNet RSSM", "why_new": "现有时序医学分割把时间建模在特征空间 3D-UNet/RNN；我把 NCA cell state 本身定义为世界状态，细胞自组织时间展开对应物理时间维——NCA-as-world-model 首次形式化，现有全部 NCA 医学分割均为单帧视角"}, "S1-05": {"one_liner": "医学世界模型每步预测附带校准置信带，让肿瘤演化预测在整条轨迹上统计有效", "problem": "arXiv:2511.16333 NeurIPS2025 Workshop 明确列出医学 WM 首要 gap: limited trajectory-level uncertainty calibration。DreamerV3 类 WM 在 OOD 医学数据上 latent 劣化但不输出校准置信度。RSSM variational filter 已被证明系统性高估 aleatoric uncertainty。肿瘤演化预测中过于自信的输出可能导致错误治疗决策。", "approach": "1: DreamerV3/RSSM 风格医学 WM latent space 增加 calibration head，用 Temperature Scaling + ensemble conformal band 同步校准；2: 纵向脑胶质瘤 MRI BraTS-Path longitudinal 训练前 t 帧预测下一帧分割+置信区间；3: 定义 trajectory coverage 指标，对比 ensemble DreamerV3 MC-Dropout TaDiff", "why_new": "现有医学 WM 只求点估计精度或生成质量；我从轨迹级 calibration 角度要求每步置信带在整条轨迹上统计有效——trajectory-calibrated world model，现有医学 WM 无一形式化此目标"}, "S1-06": {"one_liner": "干预条件世界模型：预测切除这块肿瘤后边界如何变化，并报告每种手术方案的不确定性", "problem": "arXiv:2511.16333 把 intervention simulation L3 反事实推理标为医学 WM 关键缺失能力，大多数系统只达 L1-L2。See-Predict-Plan MICCAI2024 虽做程序规划但完全确定性。weak interventional validation 是 arXiv:2511.16333 明确列出的 gap。分割不确定性从未传播到干预决策中。", "approach": "1: 建立干预条件 WM：latent state=分割掩码+解剖特征，action space=离散手术动作，dynamics model 预测干预后分割状态分布；2: CholecT50+NIH 腹部 CT 配对数据训练；3: 评估术后分割 Dice + 不确定性传播，对比 See-Predict-Plan 和 TaDiff", "why_new": "现有方法把分割和干预规划当独立问题；我把分割不确定性作为干预决策显式输入，WM 回答高不确定区域手术的风险置信带——uncertainty-propagating intervention WM，跨越分割-规划鸿沟"}, "S1-07": {"one_liner": "用世界模型主动合成 OOD 医学扫描，系统绘制分割模型的真实失败边界能力相图", "problem": "arXiv:2311.11096 指出现有医学分割鲁棒性评估只用真实 OOD 数据集，无法系统探索失败边界覆盖不完整。OOD 医学数据收集昂贵且伦理受限。arXiv:2511.16333 把 stress-testing OOD shifts 列为 future work，当前生成模型用于 counterfactual stress-testing 的方法论尚未建立。", "approach": "1: 训练 latent diffusion WM 通过 action-conditioning 生成扫描仪切换/对比度异常/解剖变异等 OOD 场景；2: 用生成 OOD 对 nnUNet/SAM-Med/Med-NCA 系统化测试，绘制 OOD 严重度 vs Dice 衰减能力相图；3: 验证生成 OOD 能复现真实 OOD 失败模式，并发现真实数据覆盖不到的新失败模式", "why_new": "现有鲁棒性评估从找现有 OOD 数据集角度；我从用 WM 主动生成有目的对抗 OOD 角度，把 WM 当失败探测器——WM-as-stress-tester 视角，与 MedAD-FailMap 互补不重叠"}}'
data=json.loads(DATA_S)
with open(p,"r",encoding="utf-8") as f2: rows=[json.loads(l) for l in f2 if l.strip()]
idx={r["id"]:r for r in rows}
for id,u in data.items():
    if id in idx: idx[id].update(u)
with open(p,"w",encoding="utf-8") as f2:
    for r in rows: f2.write(json.dumps(r,ensure_ascii=False)+chr(10))
print("batch1 done",len(rows))
